import { useEffect, useState } from "react";
import axios from "axios";
import { Link } from "react-router-dom";

function Dashboard() {

  const token = localStorage.getItem("token");
  if (!token) {
    window.location.href = "/";
  }

  const user = JSON.parse(localStorage.getItem("user"));

  const [appointments, setAppointments] = useState([]);

  useEffect(() => {
    axios.get("http://localhost:5000/api/appointments", {
      params: {
        userId: user?._id,
        role: user?.role,
        name: user?.name
      }
    })
    .then(res => setAppointments(res.data));
  }, []);

  const logout = () => {
    localStorage.clear();
    window.location.href = "/";
  };

  // ================= COMMON =================
  const today = new Date().toISOString().split("T")[0];

  // ================= PATIENT LOGIC =================
  const pending = appointments.filter(a => a.status === "pending");
  const accepted = appointments.filter(a => a.status === "accepted");
  const total = appointments.length;
  const upcoming = accepted;

  // ================= DOCTOR LOGIC =================
  const docTotal = appointments.length;

  const docAccepted = appointments.filter(a => a.status === "accepted");

  const docPending = appointments.filter(a => a.status === "pending");

  const docCompleted = appointments.filter(
    a => a.status === "accepted" && a.date < today
  );

  const todayAppointments = appointments.filter(
    a => a.date === today
  );

  return (
    <div className="layout">

      {/* Sidebar */}
      <div className="sidebar">
        <h2>🏥 MediCare</h2>

        <Link to="/dashboard">🏠 Dashboard</Link>

        {user?.role === "patient" && (
          <>
            <Link to="/doctors">👨‍⚕️ Doctors</Link>
            <Link to="/book">📅 Book Appointment</Link>
          </>
        )}

        <Link to="/appointments">📋 Appointments</Link>

        <button onClick={logout}>🚪 Logout</button>
      </div>

      {/* MAIN */}
      <div className="main">

        <div className="header">
          <h2>Welcome {user?.name} 👋</h2>
          <p>Role: {user?.role}</p>
        </div>

        {/* ================= PATIENT DASHBOARD ================= */}
        {user?.role === "patient" && (
          <>
            <div className="cards">

              <div className="card-box">
                <h3>🟡 Pending appointments</h3>
                <p>{pending.length}</p>
              </div>

              <div className="card-box">
                <h3>🟢 Ongoing appointments</h3>
                <p>{accepted.length}</p>
              </div>

              <div className="card-box">
                <h3>📊 Total appointments</h3>
                <p>{total}</p>
              </div>

            </div>

            <div style={{ marginTop: "30px" }}>
              <h2>Upcoming Appointments</h2>

              {upcoming.length === 0 ? (
                <div className="card-box" style={{ width: "300px" }}>
                  <p>No upcoming appointments</p>

                  <button onClick={() => window.location.href = "/book"}>
                    Book Appointment
                  </button>
                </div>
              ) : (
                <div className="cards">
                  {upcoming.map(a => (
                    <div key={a._id} className="card-box">
                      <p><b>Doctor:</b> {a.doctorName}</p>
                      <p><b>Date:</b> {a.date}</p>
                      <p><b>Time:</b> {a.time}</p>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </>
        )}

        {/* ================= DOCTOR DASHBOARD ================= */}
        {user?.role === "doctor" && (
          <>
            {/* 🔝 TOP HALF */}
            <div className="cards">

              <div className="card-box">
                <h3>📊 Total appointments</h3>
                <p>{docTotal}</p>
              </div>

              <div className="card-box">
                <h3>✅ Accepted appointments</h3>
                <p>{docAccepted.length}</p>
              </div>

              <div className="card-box">
                <h3>🟡 Pending appointments</h3>
                <p>{docPending.length}</p>
              </div>

              <div className="card-box">
                <h3>✔️ Completed appointments</h3>
                <p>{docCompleted.length}</p>
              </div>

            </div>

            {/* 🔽 BOTTOM HALF */}
            <div style={{ marginTop: "30px" }}>
              <h2>Today's Appointments</h2>

              {todayAppointments.length === 0 ? (
                <div className="card-box" style={{ width: "300px" }}>
                  <p>No appointments today</p>
                </div>
              ) : (
                <div className="cards">
                  {todayAppointments.map(a => (
                    <div key={a._id} className="card-box">
                      <p><b>Patient:</b> {a.patientName}</p>
                      <p><b>Time:</b> {a.time}</p>
                      <p><b>Problem:</b> {a.problem}</p>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </>
        )}

      </div>
    </div>
  );
}

export default Dashboard;
